import React from "react";
import styles from './MapComponent.module.scss';

const MapComponent = () => {
  return(
    <div className={styles.objectsMap}>
      <div className={styles.objectsContent}>
        <script type="text/javascript" charset="utf-8" async src="https://api-maps.yandex.ru/services/constructor/1.0/js/?um=constructor%3Ab643d8589e049e46f4aecc1bb5c2e49382a0ee82c2d30f6ea4d64ed92d8a3e28&amp;width=1210&amp;height=520&amp;lang=ru_RU&amp;scroll=true"></script>
      </div>
    </div>
  );
}

export default MapComponent;
